parameters.jsCode:
const response = $input.first().json;
const raw = response.text || response.content || (Array.isArray(response.content) ? response.content[0]?.text : '') || '';

let tasks = [];
try {
  const match = raw.match(/\[.*\]/s);
  if (match) tasks = JSON.parse(match[0]);
} catch(e) { tasks = [{ title: 'משימה חדשה מהמסמך', type: 'homework', due_date_offset_days: 0 }]; }

if (!tasks.length) tasks = [{ title: 'משימה חדשה', type: 'homework', due_date_offset_days: 0 }];

const now = Math.floor(Date.now() / 1000);
const DAY = 86400;
const childId = $node['Parse Input'].json.child_id;
const authToken = $node['Parse Input'].json.auth_token;

return tasks.map(t => ({
  json: {
    title: t.title || 'משימה חדשה',
    type: ['homework','test','activity','other'].includes(t.type) ? t.type : 'homework',
    status: 'pending',
    due_date: now + ((t.due_date_offset_days || 0) * DAY),
    child_id: childId,
    auth_token: authToken
  }
}));
